out vec4 fragColor;
float hash(vec2 p){ return fract(sin(dot(p, vec2(127.1, 311.7)))*43758.5453); }
float noise(vec2 p){
    vec2 i = floor(p), f = fract(p);
    vec2 u = f*f*(3.0 - 2.0*f);
    return mix(mix(hash(i), hash(i+vec2(1.0,0.0)), u.x),
               mix(hash(i+vec2(0.0,1.0)), hash(i+vec2(1.0,1.0)), u.x), u.y);
}
float fbm(vec2 p){
    float v = 0.0, a = 0.5;
    for(int i = 0; i < 6; i++){ v += a*noise(p); p = p*2.02 + 11.3; a *= 0.5; }
    return v;
}
void main(){
    vec2 uv = vUV.st;
    vec2 p = uv*3.0;
    // domain warp for organic, non-grid filaments
    float w = fbm(p + vec2(fbm(p+1.7), fbm(p+9.2))*1.5);
    // bright thin streaks: ridge the warped field so filaments pop
    float ridge = 1.0 - abs(2.0*w - 1.0);
    ridge = pow(clamp(ridge, 0.0, 1.0), 3.0);
    vec3 col = vec3(0.06, 0.10, 0.16) + ridge*vec3(0.95, 0.85, 0.70);
    fragColor = vec4(col, 1.0);
}

uniform vec4 uParams;   // x=swirl(rad/frame), y=zoom(<1 pulls in), z=seedmix, w=time
out vec4 fragColor;
void main(){
    float t       = uParams.w;
    float swirl   = uParams.x;
    float zoom    = uParams.y;
    float seedmix = uParams.z;
    vec2 uv = vUV.st - 0.5;
    float r = length(uv);
    float a = atan(uv.y, uv.x);
    // spiral: rotate more near the center, pull radius inward (zoom<1)
    float swirlR = swirl * (1.0 + 1.6*(1.0 - r));   // stronger twist at the core
    a += swirlR;
    r *= zoom;
    // slow global breathing so it never settles to a fixed point
    a += 0.15*sin(t*0.05);
    vec2 sp = vec2(cos(a), sin(a))*r + 0.5;
    vec4 prev = texture(sTD2DInputs[0], sp);     // last frame (fed back, decayed)
    vec4 seed = texture(sTD2DInputs[1], vUV.st); // static seed
    // thread the seed back in so the vortex regenerates instead of draining
    vec3 col = mix(prev.rgb, max(prev.rgb, seed.rgb), seedmix);
    fragColor = vec4(col, 1.0);
}

uniform vec4 uPal;   // x = hue shift 0..1
out vec4 fragColor;
vec3 hue(vec3 c, float h){
    const vec3 k = vec3(0.57735);
    float ca = cos(h*6.2831853), sa = sin(h*6.2831853);
    return c*ca + cross(k, c)*sa + k*dot(k, c)*(1.0 - ca);
}
void main(){
    vec2 uv = vUV.st;
    vec3 s = texture(sTD2DInputs[0], uv).rgb;
    float lum = dot(s, vec3(0.299, 0.587, 0.114));
    // palette ramp: deep core -> teal -> warm rim, driven by luminance
    vec3 c0 = vec3(0.02, 0.03, 0.08);
    vec3 c1 = vec3(0.10, 0.45, 0.55);
    vec3 c2 = vec3(1.00, 0.80, 0.45);
    vec3 col = mix(c0, c1, smoothstep(0.0, 0.45, lum));
    col = mix(col, c2, smoothstep(0.45, 0.85, lum));
    col = hue(col, uPal.x);
    // center bloom glow
    float d = distance(uv, vec2(0.5));
    col += vec3(0.6, 0.5, 0.35) * pow(max(0.0, 1.0 - d*2.2), 3.0) * lum;
    // soft vignette
    col *= mix(1.0, 0.45, smoothstep(0.35, 0.95, d));
    fragColor = vec4(clamp(col, 0.0, 1.0), 1.0);
}
